package com.clashcoach.recommendation; import com.clashcoach.player.PlayerSnapshot; import javax.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="recommendations") public class Recommendation { @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="snapshot_id",nullable=false) private PlayerSnapshot snapshot; @Column(name="recommendation_type",nullable=false) private String type; @Column(nullable=false) private String priority; @Column(name="reason_codes_json",nullable=false,columnDefinition="jsonb") private String reasonCodesJson; @Column(nullable=false) private String explanation; @Column(name="rule_version",nullable=false) private String ruleVersion; @Column(name="created_at",nullable=false) private Instant createdAt; protected Recommendation(){} public Recommendation(PlayerSnapshot snapshot,String type,String priority,String codes,String explanation,String ruleVersion){id=UUID.randomUUID();this.snapshot=snapshot;this.type=type;this.priority=priority;reasonCodesJson=codes;this.explanation=explanation;this.ruleVersion=ruleVersion;createdAt=Instant.now();} public String getType(){return type;} public String getPriority(){return priority;} public String getReasonCodesJson(){return reasonCodesJson;} public String getExplanation(){return explanation;} public String getRuleVersion(){return ruleVersion;} }
